# --- Input Sanitization ---

def sanitize_string(value):
    """Sanitize string input to prevent injection attacks."""
    if value is None:
        return None
    if not isinstance(value, str):
        return str(value)
    # Strip leading/trailing whitespace
    value = value.strip()
    # HTML-encode to prevent XSS in any downstream rendering
    value = html.escape(value, quote=True)
    # Limit length
    return value[:1000]


def validate_pagination(first, offset, max_page_size=None):
    """Validate and constrain pagination parameters."""
    if max_page_size is None:
        max_page_size = Config.MAX_PAGE_SIZE
    
    if first is not None:
        if first < 0:
            first = Config.DEFAULT_PAGE_SIZE
        first = min(first, max_page_size)
    else:
        first = Config.DEFAULT_PAGE_SIZE
    
    if offset is not None:
        if offset < 0:
            offset = 0
    else:
        offset = 0
    
    return first, offset


def validate_rating(rating):
    """Validate rating is within acceptable range."""
    if rating is not None:
        if not isinstance(rating, int) or rating < 1 or rating > 5:
            raise ValueError("Rating must be an integer between 1 and 5")
    return rating


# --- Query Depth Analysis ---

def get_query_depth(query_string):
    """Estimate the depth of a GraphQL query to prevent deeply nested attacks."""
    depth = 0
    max_depth = 0
    for char in query_string:
        if char == '{':
            depth += 1
            max_depth = max(max_depth, depth)
        elif char == '}':
            depth -= 1
    return max_depth


# --- Rate Limiting (simple in-memory, use Redis in production) ---

from collections import defaultdict
import time
import threading

class RateLimiter:
    """Simple thread-safe in-memory rate limiter."""
    
    def __init__(self, max_requests=60, window_seconds=60):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self._requests = defaultdict(list)
        self._lock = threading.Lock()
    
    def is_allowed(self, client_id):
        """Check if a request from client_id is allowed."""
        now = time.time()
        with self._lock:
            # Clean old entries
            self._requests[client_id] = [
                t for t in self._requests[client_id]
                if now - t < self.window_seconds
            ]
            if len(self._requests[client_id]) >= self.max_requests:
                return False
            self._requests[client_id].append(now)
            return True

rate_limiter = RateLimiter(max_requests=Config.RATE_LIMIT)


